function clb = fGetClbGuiV01(fName,nmb)%% get calibration data from Giullaume's config file%% clb = fGetRangeGuiV01(fName,nmb)%% fName: file name (full path)% nmb:  number of line (89 for calibration)% clb:  array 1:clb-x, 2:clb-y%% Function fGetClbGuiV01.m % get calibration from Guillaume configration file, ver.1% Kei Nakamura% Created on Friday, february 18th 2011.% Modified on %% ver.1: created%% main bodylin = fGetTextLineV01(fName,nmb);   % get a linek = find(double(lin)==61);    % find tubclb(2) = str2double(lin(k(1)+1:end));lin = fGetTextLineV01(fName,nmb+1);   % get a linek = find(double(lin)==61);    % find tubclb(1) = str2double(lin(k(1)+1:end));
